1	import { spawn } from "node:child_process";
2	import { existsSync, readFileSync, readdirSync } from "node:fs";
3	import os from "node:os";
4	import path from "node:path";
5	import type { RouterConfig } from "./config.js";
6	import { isKnownVersion, readCompatibility } from "./compatibility.js";
7	
8	export interface ClaudeJsonResponse {
9	  sessionId: string;
10	  result: string;
11	  tokensIn?: number;
12	  tokensOut?: number;
13	}
14	
15	export interface ClaudePromptOptions {
16	  resumeSessionId?: string;
17	  extraArgs?: string[];
18	  includeConfiguredExtraArgs?: boolean;
19	  appendSystemPrompt?: string;
20	}
21	
22	export interface HealthProbeResult {
23	  ok: boolean;
24	  degraded: boolean;
25	  detectedVersion?: string;
26	  testedVersions: string[];
27	  unknownVersion: boolean;
28	  error?: string;
29	}
30	
31	export interface ClaudeAdapter {
32	  getVersion(): Promise<string>;
33	  runPrompt(prompt: string, resumeSessionId?: string): Promise<ClaudeJsonResponse>;
34	  runPromptWithOptions?(prompt: string, options: ClaudePromptOptions): Promise<ClaudeJsonResponse>;
35	  healthProbe(): Promise<HealthProbeResult>;
36	  sessionFileExists(claudeSessionId: string): Promise<boolean>;
37	}
38	
39	export class CliClaudeAdapter implements ClaudeAdapter {
40	  constructor(private readonly config: RouterConfig) {}
41	
42	  async getVersion(): Promise<string> {
43	    return (await runCommand(this.config.claude.command, ["--version"], this.config.claude.commandTimeoutMs)).trim();
44	  }
45	
46	  async runPrompt(prompt: string, resumeSessionId?: string): Promise<ClaudeJsonResponse> {
47	    return this.runPromptWithOptions(prompt, { resumeSessionId });
48	  }
49	
50	  async runPromptWithOptions(prompt: string, options: ClaudePromptOptions = {}): Promise<ClaudeJsonResponse> {
51	    const args = [
52	      "-p",
53	      ...(options.includeConfiguredExtraArgs === false ? [] : this.config.claude.extraArgs),
54	      ...(options.extraArgs ?? []),
55	      "--output-format",
56	      this.config.claude.outputFormat
57	    ];
58	    if (options.appendSystemPrompt) {
59	      args.push("--append-system-prompt", options.appendSystemPrompt);
60	    }
61	    if (options.resumeSessionId) {
62	      args.push("--resume", options.resumeSessionId);
63	    }
64	    args.push(prompt);
65	
66	    const stdout = await runCommand(this.config.claude.command, args, this.config.claude.commandTimeoutMs);
67	    return parseClaudeJson(stdout);
68	  }
69	
70	  async healthProbe(): Promise<HealthProbeResult> {
71	    const compatibility = readCompatibility(this.config.claude.compatibilityFile);
72	    const testedVersions = compatibility.testedClaudeVersions;
73	    let detectedVersion: string | undefined;
74	    let unknownVersion = false;
75	
76	    try {
77	      detectedVersion = await this.getVersion();
78	      unknownVersion = !isKnownVersion(detectedVersion, testedVersions);
79	      await this.runPrompt("ping");
80	      const fixtureId = this.readFixtureSessionId();
81	      if (fixtureId) {
82	        await this.runPrompt("ping", fixtureId);
83	      }
84	
85	      return {
86	        ok: true,
87	        degraded: false,
88	        detectedVersion,
89	        testedVersions,
90	        unknownVersion
91	      };
92	    } catch (error: unknown) {
93	      return {
94	        ok: false,
95	        degraded: true,
96	        detectedVersion,
97	        testedVersions,
98	        unknownVersion,
99	        error: error instanceof Error ? error.message : String(error)
100	      };
101	    }
102	  }
103	
104	  async sessionFileExists(claudeSessionId: string): Promise<boolean> {
105	    const home = os.homedir();
106	    const candidates = [
107	      path.join(home, ".claude", "sessions", `${claudeSessionId}.json`),
108	      path.join(home, ".claude", "sessions", `${claudeSessionId}.jsonl`),
109	      path.join(home, ".claude", "projects")
110	    ];
111	
112	    if (existsSync(candidates[0]) || existsSync(candidates[1])) {
113	      return true;
114	    }
115	
116	    const projectsDir = candidates[2];
117	    if (!existsSync(projectsDir)) {
118	      return false;
119	    }
120	
121	    return findFile(projectsDir, `${claudeSessionId}.jsonl`, 3);
122	  }
123	
124	  private readFixtureSessionId(): string | null {
125	    const fixturePath = path.join(path.dirname(this.config.storage.dbPath), "fixture_resume_session_id.txt");
126	    if (!existsSync(fixturePath)) {
127	      return null;
128	    }
129	    const fixtureId = readFileSync(fixturePath, "utf8").trim();
130	    return fixtureId || null;
131	  }
132	}
133	
134	export function parseClaudeJson(stdout: string): ClaudeJsonResponse {
135	  const parsed: unknown = JSON.parse(stdout);
136	  if (!isObject(parsed)) {
137	    throw new Error("Claude JSON response was not an object");
138	  }
139	
140	  const sessionId = stringField(parsed, "session_id") ?? stringField(parsed, "sessionId");
141	  const result = stringField(parsed, "result") ?? stringField(parsed, "text") ?? stringField(parsed, "answer");
142	  if (!sessionId || !result) {
143	    throw new Error("Claude JSON response missing session_id or result");
144	  }
145	  if (parsed.is_error === true) {
146	    throw new Error(`Claude CLI returned error result: ${result}`);
147	  }
148	
149	  return {
150	    sessionId,
151	    result,
152	    tokensIn:
153	      numberField(parsed, "tokens_in") ??
154	      numberField(parsed, "input_tokens") ??
155	      numberField(objectField(parsed, "usage"), "input_tokens") ??
156	      undefined,
157	    tokensOut:
158	      numberField(parsed, "tokens_out") ??
159	      numberField(parsed, "output_tokens") ??
160	      numberField(objectField(parsed, "usage"), "output_tokens") ??
161	      undefined
162	  };
163	}
164	
165	function findFile(dir: string, fileName: string, remainingDepth: number): boolean {
166	  if (remainingDepth < 0) {
167	    return false;
168	  }
169	
170	  for (const entry of readdirSync(dir, { withFileTypes: true })) {
171	    const fullPath = path.join(dir, entry.name);
172	    if (entry.isFile() && entry.name === fileName) {
173	      return true;
174	    }
175	    if (entry.isDirectory() && findFile(fullPath, fileName, remainingDepth - 1)) {
176	      return true;
177	    }
178	  }
179	
180	  return false;
181	}
182	
183	function isObject(value: unknown): value is Record<string, unknown> {
184	  return typeof value === "object" && value !== null && !Array.isArray(value);
185	}
186	
187	function stringField(source: Record<string, unknown>, key: string): string | null {
188	  const value = source[key];
189	  return typeof value === "string" ? value : null;
190	}
191	
192	function numberField(source: Record<string, unknown>, key: string): number | null {
193	  const value = source[key];
194	  return typeof value === "number" && Number.isFinite(value) ? value : null;
195	}
196	
197	function objectField(source: Record<string, unknown>, key: string): Record<string, unknown> {
198	  const value = source[key];
199	  return isObject(value) ? value : {};
200	}
201	
202	function runCommand(command: string, args: string[], timeoutMs: number): Promise<string> {
203	  return new Promise((resolve, reject) => {
204	    const child = spawn(command, args, {
205	      stdio: ["pipe", "pipe", "pipe"],
206	      windowsHide: true
207	    });
208	
209	    let stdout = "";
210	    let stderr = "";
211	    let timedOut = false;
212	    let killTimer: NodeJS.Timeout | null = null;
213	    const timer =
214	      timeoutMs > 0
215	        ? setTimeout(() => {
216	            timedOut = true;
217	            child.kill("SIGTERM");
218	            killTimer = setTimeout(() => {
219	              child.kill("SIGKILL");
220	            }, 2_000);
221	            killTimer.unref();
222	          }, timeoutMs)
223	        : null;
224	    timer?.unref();
225	
226	    child.stdout.setEncoding("utf8");
227	    child.stderr.setEncoding("utf8");
228	    child.stdout.on("data", (chunk) => {
229	      stdout += chunk;
230	    });
231	    child.stderr.on("data", (chunk) => {
232	      stderr += chunk;
233	    });
234	    child.on("error", (error) => {
235	      if (timer) {
236	        clearTimeout(timer);
237	      }
238	      if (killTimer) {
239	        clearTimeout(killTimer);
240	      }
241	      reject(error);
242	    });
243	    child.on("close", (code) => {
244	      if (timer) {
245	        clearTimeout(timer);
246	      }
247	      if (killTimer) {
248	        clearTimeout(killTimer);
249	      }
250	      if (timedOut) {
251	        reject(
252	          new Error(
253	            `Command timed out after ${timeoutMs}ms: ${command} ${formatArgsForError(args)}`
254	          )
