266	export function verifyFactsheetStatic(
267	  cwd: string,
268	  clusterId: string,
269	  factsheet: FactsheetInput
270	): StaticFactsheetVerification {
271	  if (factsheet.cluster_id && factsheet.cluster_id !== clusterId) {
272	    throw new Error(`factsheet cluster_id ${factsheet.cluster_id} does not match ${clusterId}`);
273	  }
274	
275	  const facts = Array.isArray(factsheet.facts) ? factsheet.facts : [];
276	  const verifiedFacts: VerifiedFactsheet["facts"] = [];
277	  const rejectedFacts: RejectedFact[] = [];
278	  const fileHashes = new Map<string, { path: string; hash: string; fileSize: number }>();
279	
280	  for (const fact of facts) {
281	    const factId = stringOrEmpty(fact.id);
282	    const claim = stringOrEmpty(fact.claim);
283	    const evidence = Array.isArray(fact.evidence) ? fact.evidence : [];
284	    if (!factId || !claim || evidence.length === 0) {
285	      rejectedFacts.push({
286	        id: factId || "missing-id",
287	        claim,
288	        reason: "fact requires id, claim, and at least one evidence entry"
289	      });
290	      continue;
291	    }
292	
293	    const verifiedEvidence: VerifiedFactsheet["facts"][number]["evidence"] = [];
294	    const rejectionReasons: string[] = [];
295	    for (const item of evidence) {
296	      try {
297	        const file = readVerifiedEvidenceFile(cwd, item.path);
298	        const selector = item.selector ? String(item.selector) : undefined;
299	        if (selector && !file.content.includes(selector)) {
300	          rejectionReasons.push(`selector not found in ${file.path}: ${selector}`);
301	          continue;
302	        }
303	        if (item.hash && normalizeEvidenceHash(item.hash) !== `sha256:${file.hash}`) {
304	          rejectionReasons.push(`hash mismatch for ${file.path}`);
305	          continue;
306	        }
307	        const snippet = selector ? buildEvidenceSnippet(file.content, selector) : null;
308	        if (item.snippet_hash && snippet && item.snippet_hash !== snippet.hash) {
309	          rejectionReasons.push(`snippet hash mismatch for ${file.path}: ${selector}`);
310	          continue;
311	        }
312	        verifiedEvidence.push({
313	          path: file.path,
314	          hash: `sha256:${file.hash}`,
315	          ...(selector ? { selector, snippet_hash: snippet?.hash } : {})
316	        });
317	        fileHashes.set(file.path, {
318	          path: file.path,
319	          hash: `sha256:${file.hash}`,
320	          fileSize: file.fileSize
321	        });
322	      } catch (error: unknown) {
323	        rejectionReasons.push(error instanceof Error ? error.message : String(error));
324	      }
325	    }
326	
327	    if (verifiedEvidence.length !== evidence.length) {
328	      rejectedFacts.push({
329	        id: factId,
330	        claim,
331	        reason: rejectionReasons.join("; ") || "not all evidence entries verified"
332	      });
333	      continue;
334	    }
335	
336	    verifiedFacts.push({
337	      id: factId,
338	      claim,
339	      confidence: "static_verified",
340	      evidence: verifiedEvidence
341	    });
342	  }
343	
344	  return {
345	    factsheet: {
346	      schema_version: 1,
347	      cluster_id: clusterId,
348	      summary: stringOrEmpty(factsheet.summary).slice(0, 500),
349	      facts: verifiedFacts,
350	      pitfalls: sanitizePitfalls(factsheet.pitfalls),
351	      forbidden_inferences: sanitizeStringArray(factsheet.forbidden_inferences, 20, 300),
352	      omitted_facts: rejectedFacts.length
353	    },
354	    fileHashes: [...fileHashes.values()],
355	    rejectedFacts
356	  };
357	}
358	
359	export async function verifyFactsheetWithLlm(
360	  claude: ClaudeAdapter,
361	  cwd: string,
362	  factsheet: VerifiedFactsheet,
363	  toolProfile: VerifierToolProfile
364	): Promise<LlmFactsheetVerification> {
365	  const prompt = buildLlmVerifierPrompt(cwd, factsheet);
366	  const start = Date.now();
367	  const response =
368	    claude.runPromptWithOptions !== undefined
369	      ? await claude.runPromptWithOptions(prompt, profilePromptOptions(toolProfile))
370	      : await claude.runPrompt(prompt);
371	  const durationMs = Date.now() - start;
372	  const verifierResults = parseLlmVerifierResponse(response.result);
373	  const resultById = new Map(verifierResults.map((result) => [result.id, result]));
374	  const promotedFacts: VerifiedFactsheet["facts"] = [];
375	  const rejectedFacts: RejectedFact[] = [];
376	
377	  for (const fact of factsheet.facts) {
378	    const verdict = resultById.get(fact.id);
379	    if (verdict?.verdict === "VERIFIED") {
380	      promotedFacts.push({
381	        ...fact,
382	        confidence: "llm_verified"
383	      });
384	      continue;
385	    }
386	    rejectedFacts.push({
387	      id: fact.id,
388	      claim: fact.claim,
389	      reason: `llm_verifier:${verdict?.verdict ?? "MISSING"} ${verdict?.reason ?? "verifier did not return this fact"}`
390	    });
391	  }
392	
393	  return {
394	    factsheet: {
395	      ...factsheet,
396	      facts: promotedFacts,
