353	  applyLifecycle(projectId?: string): void {
354	    const sessions = this.selectLifecycleSessions(projectId);
355	    for (const session of sessions) {
356	      const ageDays = daysBetweenIso(this.clock, session.last_used);
357	      if (ageDays >= session.archive_after_days && session.status !== "archived") {
358	        const archivedAt = this.clock.nowIso();
359	        this.db
360	          .prepare("UPDATE sessions SET status = 'archived', archived_at = ? WHERE id = ?")
361	          .run(archivedAt, session.id);
362	        this.logEvent({
363	          sessionId: session.id,
364	          projectId: session.project_id,
365	          eventType: "archive",
366	          error: "lifecycle_archive_after_days"
367	        });
368	      } else if (ageDays >= session.dormant_after_days && session.status === "active") {
369	        this.db.prepare("UPDATE sessions SET status = 'dormant' WHERE id = ?").run(session.id);
370	        this.logEvent({
371	          sessionId: session.id,
372	          projectId: session.project_id,
373	          eventType: "dormant",
374	          error: "lifecycle_dormant_after_days"
375	        });
376	      }
377	    }
378	  }
