738	  insertClusterFactsheet(input: ClusterFactsheetInput): ClusterFactsheetRecord {
739	    const insert = this.db.transaction(() => {
740	      const versionRow = this.db
741	        .prepare("SELECT MAX(version) AS maxVersion FROM cluster_factsheets WHERE cluster_id = ?")
742	        .get(input.clusterId) as { maxVersion: number | null };
743	      const version = (versionRow.maxVersion ?? 0) + 1;
744	      const now = this.clock.nowIso();
745	
746	      this.db
747	        .prepare(
748	          `INSERT INTO cluster_factsheets (
749	            id,
750	            cluster_id,
751	            version,
752	            content_json,
753	            source_session_id,
754	            baseline_session_id,
755	            git_rev,
756	            generated_at,
757	            verified_at,
758	            status
759	          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
760	        )
761	        .run(
762	          input.id,
763	          input.clusterId,
764	          version,
765	          input.contentJson,
766	          input.sourceSessionId ?? null,
767	          input.baselineSessionId ?? null,
768	          input.gitRev ?? null,
769	          now,
770	          isVerifiedFactsheetStatus(input.status) ? now : null,
771	          input.status
772	        );
773	
774	      for (const file of input.fileHashes) {
775	        this.db
776	          .prepare(
777	            `INSERT INTO cluster_file_hashes (
778	              cluster_id,
779	              factsheet_id,
780	              path,
781	              hash,
782	              file_size,
783	              last_verified
784	            ) VALUES (?, ?, ?, ?, ?, ?)`
785	          )
786	          .run(input.clusterId, input.id, file.path, file.hash, file.fileSize, now);
787	      }
788	
789	      const trustState: ClusterTrustState =
790	        input.trustState ??
791	        (input.status === "llm_verified"
792	          ? "llm_verified"
793	          : input.status === "static_verified"
794	            ? "static_verified"
795	            : "untrusted");
796	      this.db
797	        .prepare("UPDATE clusters SET status = 'active', trust_state = ?, last_used = ? WHERE id = ?")
798	        .run(trustState, now, input.clusterId);
799	
800	      return this.getClusterFactsheet(input.id)!;
801	    });
802	
803	    const factsheet = insert();
804	    this.logClusterEvent({
805	      clusterId: input.clusterId,
806	      projectId: this.getClusterById(input.clusterId)?.project_id ?? "",
807	      eventType: factsheetEventType(input.status, input.trustState),
808	      details: {
809	        factsheet_id: input.id,
810	        version: factsheet.version,
811	        file_hashes: input.fileHashes.length
812	      }
813	    });
814	    return factsheet;
815	  }
