  updateConsultComparisonJudge(input: {
    id: string;
    clusterScore: number;
    directScore: number;
    preferred: ComparisonPreference;
    clusterErrors: string[];
    directErrors: string[];
    judgeReasoning: string;
  }): void {
    this.db
      .prepare(
        `UPDATE consult_comparisons
         SET cluster_score = ?,
             direct_score = ?,
             preferred = ?,
             cluster_errors_json = ?,
             direct_errors_json = ?,
             judge_reasoning = ?,
             judged_at = ?
         WHERE id = ?`
      )
      .run(
        input.clusterScore,
