868	function countMap(rows: StatusCount[], keys: readonly string[]): Record<string, number> {
869	  const counts: Record<string, number> = {};
870	  for (const key of keys) {
871	    counts[key] = 0;
872	  }
873	  for (const row of rows) {
874	    counts[row.status] = row.count;
875	  }
876	  return counts;
877	}
