887	function buildStatusWarnings(input: {
888	  degradedMode: boolean;
889	  degradedReason?: string;
890	  staleClusters: StaleClusterView[];
891	  sessionErrors: EventCount[];
892	  clusterAttention: EventCount[];
893	  shadowEval: ShadowEvalHealth;
894	  shadowEnabled: boolean;
895	  limit: number;
896	}): string[] {
897	  const warnings: string[] = [];
898	  if (input.degradedMode) {
899	    warnings.push(`Router is degraded: ${input.degradedReason ?? "unknown reason"}`);
900	  }
901	  for (const cluster of input.staleClusters) {
902	    warnings.push(
903	      `Cluster '${cluster.id}' is stale; latest factsheet ${cluster.factsheet_id ?? "unknown"} version ${
904	        cluster.factsheet_version ?? "unknown"
905	      } needs refresh or re-prepare.`
906	    );
907	  }
908	  for (const event of input.clusterAttention) {
909	    warnings.push(`Cluster event '${event.event_type}' occurred ${event.count} time(s) in the recent window.`);
910	  }
911	  for (const event of input.sessionErrors) {
912	    warnings.push(`Session event '${event.event_type}' has ${event.count} error row(s) in the recent window.`);
913	  }
914	  if (input.shadowEnabled) {
915	    const stalled = input.shadowEval.pending + input.shadowEval.ok_unjudged;
916	    const failed = input.shadowEval.failed_auth + input.shadowEval.failed_timeout + input.shadowEval.failed_other;
917	    if (stalled > 0) {
918	      warnings.push(`Shadow eval has ${stalled} unjudged comparison(s).`);
919	    }
920	    if (failed > 0) {
921	      warnings.push(`Shadow eval has ${failed} failed shadow comparison(s).`);
922	    }
923	  }
924	  return warnings.slice(0, input.limit);
925	}
