927	function buildMonitorRecommendations(input: {
928	  degradedMode: boolean;
929	  degradedReason?: string;
930	  shadowEnabled: boolean;
931	  shadowEval: ShadowEvalHealth;
932	  staleClusters: StaleClusterView[];
933	  sessionErrors: EventCount[];
934	  clusterAttentionByCluster: ClusterEventCount[];
935	  comparisonStats: ConsultComparisonMonitorStats[];
936	}): Array<{ priority: "high" | "medium" | "low"; area: string; cluster_id?: string | null; action: string; reason: string }> {
937	  const recommendations: Array<{
938	    priority: "high" | "medium" | "low";
939	    area: string;
940	    cluster_id?: string | null;
941	    action: string;
942	    reason: string;
943	  }> = [];
944	
945	  if (input.degradedMode) {
946	    recommendations.push({
947	      priority: "high",
948	      area: "infrastructure",
949	      action: "Fix Claude CLI compatibility/auth and run claude_router_reset.",
950	      reason: input.degradedReason ?? "Router is in degraded mode."
951	    });
952	  }
953	
954	  if (!input.shadowEnabled) {
955	    recommendations.push({
956	      priority: "medium",
957	      area: "monitoring",
958	      action: "Enable [eval].shadow_mode when you want real quality telemetry.",
959	      reason: "Shadow eval is disabled, so comparison quality data will not accumulate."
960	    });
961	  }
962	
963	  const stalledShadow = input.shadowEval.pending + input.shadowEval.ok_unjudged;
964	  const failedShadow = input.shadowEval.failed_auth + input.shadowEval.failed_timeout + input.shadowEval.failed_other;
965	  if (stalledShadow > 0) {
966	    recommendations.push({
967	      priority: "medium",
968	      area: "monitoring",
969	      action: "Inspect comparison_list and shadow logs; judge or direct baseline may be stalled.",
970	      reason: `Shadow eval has ${stalledShadow} unjudged comparison(s).`
971	    });
972	  }
973	  if (failedShadow > 0) {
974	    recommendations.push({
975	      priority: "high",
976	      area: "monitoring",
977	      action: "Fix shadow direct baseline failures before trusting comparison coverage.",
978	      reason: `Shadow eval has ${failedShadow} failed comparison(s).`
979	    });
980	  }
981	
982	  for (const cluster of input.staleClusters) {
983	    recommendations.push({
984	      priority: "high",
985	      area: "cache",
986	      cluster_id: cluster.id,
987	      action: "Run cluster_prepare or expand/rebuild this factsheet.",
988	      reason: `Cluster is ${cluster.status}; factsheet ${cluster.factsheet_id ?? "unknown"} cannot be trusted as current cache.`
989	    });
990	  }
991	
992	  for (const event of input.clusterAttentionByCluster) {
993	    if (event.event_type === "cluster_fallback_failed") {
994	      recommendations.push({
995	        priority: "high",
996	        area: "fallback",
997	        cluster_id: event.cluster_id,
998	        action: "Investigate Claude availability and fallback path immediately.",
999	        reason: `Fallback failed ${event.count} time(s) in the recent window.`
1000	      });
1001	    } else if (event.event_type === "cluster_fallback_to_claude_consult") {
1002	      recommendations.push({
1003	        priority: "medium",
1004	        area: "cache",
1005	        cluster_id: event.cluster_id,
1006	        action: "Re-prepare or broaden this cluster if fallback is recurring.",
1007	        reason: `Router fell back to claude_consult ${event.count} time(s), meaning cache could not serve those calls.`
1008	      });
1009	    } else if (event.event_type === "evidence_revalidation_failed") {
1010	      recommendations.push({
1011	        priority: "medium",
1012	        area: "cache",
1013	        cluster_id: event.cluster_id,
1014	        action: "Refresh factsheet evidence; selectors or snippets changed.",
1015	        reason: `Strict evidence revalidation failed ${event.count} time(s).`
1016	      });
1017	    } else if (event.event_type === "tool_profile_downgraded" || event.event_type === "bare_probe_failed") {
1018	      recommendations.push({
1019	        priority: "low",
1020	        area: "profiles",
1021	        cluster_id: event.cluster_id,
1022	        action: "Check bare-profile auth/support if latency or cost regresses.",
1023	        reason: `${event.event_type} occurred ${event.count} time(s).`
1024	      });
1025	    }
1026	  }
1027	
1028	  for (const stats of input.comparisonStats) {
1029	    if ((stats.direct_wins ?? 0) > 0 && (stats.gap ?? 0) >= 0.5) {
1030	      recommendations.push({
1031	        priority: "high",
1032	        area: "quality",
1033	        cluster_id: stats.cluster_id,
1034	        action: "Inspect direct_win_samples, then expand or rebuild the cluster factsheet.",
1035	        reason: `Direct baseline is beating cluster by ${stats.gap} points on average.`
1036	      });
1037	    } else if ((stats.not_in_context ?? 0) > 0) {
1038	      recommendations.push({
1039	        priority: "medium",
1040	        area: "coverage",
1041	        cluster_id: stats.cluster_id,
1042	        action: "Inspect NOT IN CONTEXT samples and decide whether to expand factsheet or route those questions to claude_consult.",
1043	        reason: `Cluster produced ${stats.not_in_context} NOT IN CONTEXT answer(s).`
1044	      });
1045	    }
1046	  }
1047	
1048	  for (const event of input.sessionErrors) {
1049	    recommendations.push({
1050	      priority: "medium",
1051	      area: "sessions",
1052	      action: "Inspect recent session_events and raw responses.",
1053	      reason: `Session event '${event.event_type}' has ${event.count} error row(s).`
1054	    });
1055	  }
1056	
1057	  return recommendations.slice(0, 25);
1058	}
1059	
1060	function buildMonitorNextDirections(
1061	  comparisonStats: ConsultComparisonMonitorStats[],
1062	  clusterAttentionByCluster: ClusterEventCount[],
1063	  staleClusters: StaleClusterView[],
1064	  shadowEval: ShadowEvalHealth
1065	): string[] {
1066	  const directions: string[] = [];
1067	  const hasQualityData = comparisonStats.some((stats) => stats.judged > 0);
1068	  const strongClusters = comparisonStats.filter((stats) => (stats.judged ?? 0) >= 3 && (stats.gap ?? 1) <= 0);
1069	  const weakClusters = comparisonStats.filter((stats) => (stats.direct_wins ?? 0) > 0 || (stats.not_in_context ?? 0) > 0);
1070	  const fallbackClusters = new Set(
1071	    clusterAttentionByCluster
1072	      .filter((event) => event.event_type === "cluster_fallback_to_claude_consult" || event.event_type === "evidence_revalidation_failed")
1073	      .map((event) => event.cluster_id)
1074	  );
1075	
1076	  if (!hasQualityData) {
1077	    directions.push("Collect more shadow comparisons before deciding on auto-routing or factsheet expansion.");
1078	  }
1079	  if (weakClusters.length > 0) {
1080	    directions.push("Prioritize factsheet expansion or distillation for clusters where direct wins or NOT IN CONTEXT appears.");
1081	  }
1082	  if (strongClusters.length > 0 && fallbackClusters.size === 0 && staleClusters.length === 0) {
1083	    directions.push("Clusters with stable quality and no fallback are candidates for future automatic cluster routing.");
1084	  }
1085	  if (fallbackClusters.size > 0 || staleClusters.length > 0) {
1086	    directions.push("Re-prepare decayed clusters before using their data to judge routing quality.");
1087	  }
1088	  if (shadowEval.failed_auth + shadowEval.failed_timeout + shadowEval.failed_other > 0 || shadowEval.pending + shadowEval.ok_unjudged > 0) {
1089	    directions.push("Stabilize the shadow pipeline before trusting long-term trend reports.");
1090	  }
1091	  if (comparisonStats.some((stats) => (stats.judged ?? 0) >= 10 && (stats.gap ?? 1) <= 0 && (stats.not_in_context ?? 0) === 0)) {
1092	    directions.push("Fork baselines are still low priority unless monitor data shows latency/cost, not quality, is the bottleneck.");
1093	  }
1094	
1095	  return directions;
1096	}
