1114	  const content = parseFactsheetContent(factsheet);
1115	  return Array.isArray(content.facts) ? content.facts.length : 0;
1116	}
1117	
1118	function parseFactsheetContent(factsheet: ClusterFactsheetRecord): Record<string, unknown> {
1119	  try {
1120	    const parsed = JSON.parse(factsheet.content_json) as unknown;
1121	    if (typeof parsed === "object" && parsed !== null && !Array.isArray(parsed)) {
1122	      return parsed as Record<string, unknown>;
1123	    }
1124	  } catch {
1125	    return {};
1126	  }
